function on_mouse_lbtn_dblclk() {
original.SaveAs("z:\\original.jpg");
grayscale.SaveAs("z:\\grayscale.jpg");
invert.SaveAs("z:\\invert.jpg");
sepia.SaveAs("z:\\sepia.jpg");
}
</code></pre> OriginalGrayscaleInvertSepia <p></p> <p></p> <p></p> <p></p>

Arguments count <code>number</code> <p>Returns a <code>VBArray</code> so you need to use <code>.toArray()</code> on the result.</p> <p>Example</p> <pre><code>// Tracks playlist selection

var img = null;
var arr = [];
on_item_focus_change();

function on_item_focus_change() {
if (img) {
img.Dispose();
img = null;
}

arr = [];
var metadb = fb.GetFocusItem();
if (metadb) {
img = metadb.GetAlbumArt();

if (img) {
arr = img.GetColourScheme(10).toArray();
}
}
window.Repaint();
}

function on_paint(gr) {
if (img &amp;&amp; arr.length) {
gr.DrawImage(img, 0, 0, 300, 300, 0, 0, img.Width, img.Height);
for (var i = 0; i &lt; arr.length; i++) {
gr.FillRectangle(300, i * 30, window.Width - 300, 30, arr[i]);
}
}
}

function on_playlist_switch() {
on_item_focus_change();
}
</code></pre>

Arguments radius <code>number</code> Valid values <code>2</code>-<code>254</code>. <p>No return value.</p> <p>Example</p> <pre><code>// ==PREPROCESSOR==
// @name "StackBlur (image)"
// @author "marc2003"
// @import "%fb2k_component_path%helpers.txt"
// ==/PREPROCESSOR==

var img = utils.LoadImage(fb.ComponentPath + 'samples\\images\\1.webp');
var blur_img = null;
var radius = 20;

StackBlur(radius);

function StackBlur(radius) {
if (blur_img) blur_img.Dispose();
blur_img = img.Clone();
blur_img.StackBlur(radius);
}

function on_paint(gr) {
gr.DrawImage(img, 0, 0, 550, 368, 0, 0, 550, 368);
gr.DrawImage(blur_img, 0, 368, 550, 368, 0, 0, 550, 368);
gr.FillRectangle(0, 0, window.Width, 24, RGB(0, 0, 0));
gr.WriteText('Scroll mouse to change radius: ' + radius, '', RGB(255, 255, 255), 0, 0, window.Width, 24, 2, 0);
}

function on_mouse_wheel(step) {
radius += step * 5;
if (radius &lt; 2)
radius = 2;
if (radius &gt; 254)
radius = 254;
StackBlur(radius);
window.Repaint();
}
</code></pre>

Arguments id <code>number</code> <p>Returns a <code>boolean</code> value.</p> <p>Example</p> <pre><code>// ==PREPROCESSOR==
// @import "%fb2k_component_path%helpers.txt"
// ==/PREPROCESSOR==

// Click anywhere in the panel to open the menu.

function on_mouse_lbtn_up(x, y) {
var menu = window.CreatePopupMenu();

var file = fb.CreateMainMenuManager('File');
var edit = fb.CreateMainMenuManager('Edit');
var view = fb.CreateMainMenuManager('View');
var playback = fb.CreateMainMenuManager('Playback');
var library = fb.CreateMainMenuManager('Library');
var help = fb.CreateMainMenuManager('Help');

var file_popup = window.CreatePopupMenu();
var edit_popup = window.CreatePopupMenu();
var view_popup = window.CreatePopupMenu();
var playback_popup = window.CreatePopupMenu();
var library_popup = window.CreatePopupMenu();
var help_popup = window.CreatePopupMenu();

file_popup.AppendTo(menu, MF_STRING, 'File');
edit_popup.AppendTo(menu, MF_STRING, 'Edit');
view_popup.AppendTo(menu, MF_STRING, 'View');
playback_popup.AppendTo(menu, MF_STRING, 'Playback');
library_popup.AppendTo(menu, MF_STRING, 'Library');
help_popup.AppendTo(menu, MF_STRING, 'Help');

file.BuildMenu(file_popup, 1000);
edit.BuildMenu(edit_popup, 2000);
view.BuildMenu(view_popup, 3000);
playback.BuildMenu(playback_popup, 4000);
library.BuildMenu(library_popup, 5000);
help.BuildMenu(help_popup, 6000);

var idx = menu.TrackPopupMenu(x, y);
switch (true) {
case idx == 0:
break;
case idx &lt; 2000:
file.ExecuteByID(idx - 1000);
break;
case idx &lt; 3000:
edit.ExecuteByID(idx - 2000);
break;
case idx &lt; 4000:
view.ExecuteByID(idx - 3000);
break;
case idx &lt; 5000:
playback.ExecuteByID(idx - 4000);
break;
case idx &lt; 6000:
library.ExecuteByID(idx - 5000);
break;
case idx &lt; 7000:
help.ExecuteByID(idx - 6000);
break;
}

help_popup.Dispose();
library_popup.Dispose();
playback_popup.Dispose();
view_popup.Dispose();
edit_popup.Dispose();
file_popup.Dispose();

help.Dispose();
library.Dispose();
playback.Dispose();
view.Dispose();
edit.Dispose();
file.Dispose();

menu.Dispose();
}
</code></pre>

Arguments handle IMetadbHandle <p>Returns a <code>boolean</code> value.</p> <p>Example</p> <pre><code>if (handle.Compare(handle2)) {
// do something
}
</code></pre>

Arguments art_id AlbumArtId Default <code>0</code>. want_stub <code>boolean</code> Default <code>true</code>. <p>Returns an IJSImage instance or <code>null</code> on failure.</p> <p>Note</p> <p>This method can return album art from certain radio streams if the requested type is <code>Front</code>. Use on_playback_dynamic_info_track to get notified of stream artwork changes.</p> <p>Example</p> <pre><code>var image = handle.GetAlbumArt();
if (image != null) {
// The path is now a property of the image.
console.log(image.Path);
}
</code></pre>

3.1.0+3.0.x <p>Returns an IFileInfo instance.</p> <p>Note</p> <p>The previously optional <code>full_info</code> argument for retrieving oversized tags is no longer necessary with foobar2000 <code>2.0</code> so any supplied value is now ignored.</p> Arguments full_info <code>boolean</code> Default <code>false</code>. <p>Returns an IFileInfo instance or <code>null</code> on failure.</p> <p>If <code>full_info</code> is omitted or <code>false</code>, the return value is always valid.</p> <p>If <code>full_info</code> is set to <code>true</code>, the file is opened for reading and this may fail and return <code>null</code>. Therefore you must always check the return value before using it.</p> <p>Typically you'd only use <code>full_info</code> when you wanted to access tags that contain large chunks of text such as <code>LYRICS</code> which are usually hidden behind the period character ever since foobar2000 <code>1.3</code> for performance reasons.</p> <p>Example</p> DefaultFull Info <pre><code>var f = handle.GetFileInfo();

// No need to check f before using, we know it's valid
console.log(f.MetaCount);
</code></pre> <pre><code>var f = handle.GetFileInfo(true);
var lyrics_text = "";

// Must check.
if (f) {
var idx = f.MetaFind("LYRICS");
if (idx &gt; -1) {
lyrics_text = f.MetaValue(idx, 0);
}
}
</code></pre>

Arguments image_path <code>string</code> art_id AlbumArtId Default <code>0</code>. <p>No return value.</p> <p>Any errors such as invalid path, corrupt image, target file type not supporting embedded art, etc should all silently fail. Any existing artwork of the specified type will be overwritten. There is no need to remove it first.</p> <p>Example</p> <pre><code>var handle_list = plman.GetPlaylistItems(plman.ActivePlaylist);
if (handle_list.Count &gt; 0) {
var image_path = "C:\\path\\to\\image.jpg";
handle_list.AttachImage(image_path, 0);
}
handle_list.Dispose();
</code></pre>

Arguments index <code>number</code> handle IMetadbHandle <p>No return value.</p> <p>Example</p> <pre><code>var handle = ...
handle_list.InsertItem(0, handle);
</code></pre>

Arguments handle_list IMetadbHandleList <p>No return value.</p> <p>Example</p> <pre><code>var one = plman.GetPlaylistItems(0);
var two = plman.GetPlaylistItems(1);
one.MakeDifference(two);
</code></pre> <p><code>one</code> now only contains handles that were unique to <code>one</code>. Anything that also existed in <code>two</code> will have been removed. The order of items in <code>one</code> will be randomised. <code>two</code> should be untouched.</p>

Arguments handle_list IMetadbHandleList <p>No return value.</p> <p>Example</p> <pre><code>var one = plman.GetPlaylistItems(0);
var two = plman.GetPlaylistItems(1);
one.MakeIntersection(two);
</code></pre> <p><code>one</code> now only contains handles that were in BOTH <code>one</code> AND <code>two</code>. The order of items in <code>one</code> will be randomised. <code>two</code> should be untouched.</p>

Arguments pattern <code>string</code> <p>No return value.</p> <p>Example</p> <pre><code>// This ensures the handle list will
// contain no more than 1 track by the same artist.
var handle_list = fb.GetLibraryItems();
handle_list.Randomise();
handle_list.RemoveDuplicatesByFormat("%artist%");
</code></pre>

Arguments command <code>string</code> The full path to the command must be supplied. Case is not important. <p>Returns <code>true</code> if a matching command was found, <code>false</code> otherwise.</p> <p>Example</p> <pre><code>var handle_list = plman.GetPlaylistSelectedItems(plman.ActivePlaylist);
handle_list.RunContextCommand("Properties");
</code></pre>

Arguments path <code>string</code> <p>No return value.</p> <p>Saves using native foobar2000 <code>.fpl</code> format so you should use that as the file extension. The parent folder must already exist.</p> <p>Example</p> <pre><code>var handle_list = plman.GetPlaylistItems(plman.ActivePlaylist);
handle_list.SaveAs("z:\\blah.fpl");
</code></pre>

Arguments pattern <code>string</code> direction <code>number</code> Ascending while &gt; <code>0</code>. <p>No return value.</p> <p>Example</p> <pre><code>var handle_list = fb.GetLibraryItems();
var pattern = "%album artist%|%date%|%album%|%discnumber%|%tracknumber%";
handle_list.SortByFormat(pattern, 1);
</code></pre>

Arguments str <code>string</code> <p>This method is for writing tags to files. The behaviour of whatever tag names you supply match the standard <code>Properties</code> dialog.</p> <p>You must supply a stringifed <code>array</code> or <code>object</code> as per these examples:</p> <p>Example</p> ArrayObject <p>This example uses an <code>array</code> and its length must match the <code>handle list</code> count. A fail safe way of doing this is looping through the <code>handle list</code> and filling the array as you go.</p> <pre><code>// assume we've selected one album
var handle_list = plman.GetPlaylistSelectedItems(plman.ActivePlaylist);

// an empty array
var arr = [];

for (var i = 0; i &lt; handle_list.Count; i++) {
// Each element of the array must be an object
// of key names/values, indicated by the curly braces.
arr.push({
"tracknumber" : i + 1,
"totaltracks" : handle_list.Count,
"album" : "Greatest Hits", // a simple string for a single value
"genre" : ["Rock", "Hard Rock"] // use an array for multi-value tags
});
}

var str = JSON.stringify(arr);

handle_list.UpdateFileInfoFromJSON(str);
handle_list.Dispose();
</code></pre> <p>If you want to write the exact same tags to each and every track in the <code>handle list</code>, you can use an <code>object</code> instead.</p> <pre><code>var handle_list = plman.GetPlaylistSelectedItems(plman.ActivePlaylist);

var obj = {
"album" : "Greatest Hits",
"genre" : ["Rock", "Hard Rock"]
};

var str = JSON.stringify(obj);
handle_list.UpdateFileInfoFromJSON(str);
handle_list.Dispose();
</code></pre> <p>You can use blank values to clear any existing tags.</p> <p>Example</p> <pre><code>var obj = {
"album" : ""
};
</code></pre> <p>Do not try using any method of using empty objects or blank tag names to avoid tagging any files. You should filter your <code>handle list</code> first to make sure it only contains files you really want to update.</p>

Arguments handle_list IMetadbHandleList <p>Returns a <code>VBArray</code> so you need to use <code>.toArray()</code> on the result.</p> <p>Example</p> <pre><code>var handle_list = fb.GetLibraryItems();
var artists = tfo.EvalWithMetadbs(handle_list).toArray();
console.log(handle_list.Count === artists.length); // True
</code></pre>

Arguments width <code>number</code> <p>No return value.</p> <p>Use if you want multi-line tooltips.</p> <p>Example</p> <pre><code>tooltip.SetMaxWidth(800);

// Use \n as a new line separator.
tooltip.Text = "Line1\nLine2";
</code></pre>

Arguments x <code>number</code> y <code>number</code> <p>No return value.</p> <p>Note</p> <p>Check x, y positions have changed from last time otherwise it will flicker. If making the tooltip text relative to the mouse position, you must add offsets so there is no danger of it being behind the mouse pointer.</p> <p>Example</p> <pre><code>var g_tooltip = window.CreateTooltip();
var g_trackingMouse = false;
var g_oldX, g_oldY;

function on_mouse_move(x, y) {
if (!g_trackingMouse) {
g_tooltip.Activate();
g_tooltip.TrackActivate = true;
g_trackingMouse = true;
}

// Make sure the position is changed
if (g_oldX != x || g_oldY != y) {
g_tooltip.Text = "x:" + x + ", y:" + y;

// add offsets here
g_tooltip.TrackPosition(x + 20, y + 20);
g_oldX = x;
g_oldY = y;
}
}

function on_mouse_leave() {
g_trackingMouse = false;
g_tooltip.TrackActivate = false;
}
</code></pre>

Arguments window_id window.ID paths <code>array</code> An array of strings which could be files, urls, playlists. <p>Returns a unique <code>task_id</code>.</p> <p>Similar to plman.AddLocations except rather than specifiying a target playlist, you get a handle list generated from the supplied paths/urls which are sent to a new on_locations_added callback.</p> <p>Example</p> <pre><code>var files = ["z:\\1.mp3", "z:\\2.flac"];

function on_mouse_lbtn_dblclk() {
var task_id = fb.AddLocationsAsync(window.ID, files);
console.log("got task_id", task_id);
}

function on_locations_added(task_id, handle_list) {
console.log("callback task_id", task_id);
console.log(handle_list.Count);
}
</code></pre>

Arguments handle IMetadbHandle, optional <p>Returns an IMetadbHandleList instance.</p> <p>Example</p> <pre><code>var handle = fb.GetFocusItem();
var handle_list = fb.CreateHandleList(handle);
var image_path = ...
handle_list.AttachImage(image_path, 0);
handle_list.Dispose();
</code></pre>

Arguments playlistIndex <code>number</code> Must be valid. Also, it must not be an autoplaylist or have a lock in place preventing the addition of new files. paths <code>array</code> Can be file paths/urls/playlists. select <code>boolean</code> Default <code>false</code>. If <code>true</code>, the active playlist will be set to the <code>playlistIndex</code>, the items will be selected and focus will be set to the first new item. <p>No return value.</p> <p>Note</p> <p>This operation is asynchronous and may take some time to complete if it's a large array.</p> <p>Example</p> <pre><code>var arr = ["e:\\1.mp3"];
plman.AddLocations(plman.ActivePlaylist, arr);
</code></pre>

Arguments playlistIndex <code>number</code> Must be valid. flags PlaylistLockFilterMask <p>Returns <code>true</code> on success, <code>false</code> if playlist already locked.</p> <p>See plman.ShowPlaylistLockUI first as that provides a dialog and is much more user friendly!</p> <p>Note</p> <p>Before you can add a playlist lock, you must check there is no lock present already. If another component owns the lock, you have to use that component to remove it. If the lock is owned by <code>JScript Panel 3</code> then you must remove it first. This is because locks cannot be edited. You have to remove it and then add a new one with a new mask value.</p> <p>Example</p> <pre><code>function add_playlist_lock(playlistIndex, flags) {
// check if playlistIndex is valid
if (playlistIndex &gt;= 0 &amp;&amp; playlistIndex &lt; plman.PlaylistCount) {
if (plman.IsPlaylistLocked(playlistIndex)) {
if (plman.GetPlaylistLockName(playlistIndex) == 'JScript Panel 3') {
// We own this lock so we can remove it.
plman.RemovePlaylistLock(playlistIndex);
} else {
// Locked but not ours. Nothing we can do.
return false;
}
}

return plman.AddPlaylistLock(playlistIndex, flags);
}
return false;
}

// Available mask values
var PlaylistLockFilterMask = {
filter_add : 1,
filter_remove: 2,
filter_reorder: 4,
filter_replace: 8,
filter_rename: 16,
filter_remove_playlist: 32
};

// Setting a single value:
var flags = PlaylistLockFilterMask.filter_add;

// To set multiple values at once, use | like this:
var flags2 = PlaylistLockFilterMask.filter_add | PlaylistLockFilterMask.filter_remove;

// You may add a value to existing flags using a bitwise operator like this:
flags |= PlaylistLockFilterMask.filter_replace;

//To remove a value, use &amp;= and ~ like this:
flags &amp;= ~PlaylistLockFilterMask.filter_replace;
</code></pre>

Arguments playlistIndex <code>number</code> <p>Returns a PlaylistLockFilterMask or <code>-1</code> if supplied with an invalid <code>playlistIndex</code>.</p> <p>Use this to determine the type(s) of locks applied to the specified playlist.</p> <p>Example</p> <pre><code>var PlaylistLockFilterMask = {
filter_add : 1,
filter_remove: 2,
filter_reorder: 4,
filter_replace: 8,
filter_rename: 16,
filter_remove_playlist: 32,
filter_default_action: 64
};

var mask = plman.GetPlaylistLockFilterMask(plman.ActivePlaylist)
if (mask &amp; PlaylistLockFilterMask.filter_add) {
console.log("Can't add files to this playlist");
}
</code></pre>

Arguments index <code>number</code> Must be valid. <p>Returns an IMetadbHandleList instance.</p> <p>Example</p> <pre><code>var count = plman.RecyclerCount;
if (count &gt; 0) {
// retrieve handles from first deleted playlist
var handle_list = plman.GetRecyclerItems(0);
}
</code></pre>

Arguments index <code>number</code> Must be valid. <p>Example</p> <pre><code>var count = plman.RecyclerCount;
if (count &gt; 0) {
// output name of first deleted playlist
console.log(plman.GetRecyclerName(0));
}
</code></pre>

Arguments affectedItems <code>array</code> <p>No return value.</p> <p>Purges deleted playlists so they cannot be restored.</p> <p>Example</p> <pre><code>// first only
plman.RecyclerPurge([0]);

// first and third only
plman.RecyclerPurge([0,2]);

// purges all deleted playlists
var arr = [];
var count = plman.RecyclerCount;
for (var i = 0; i &lt; count; i++) {
arr.push(i);
}
plman.RecyclerPurge(arr);
</code></pre>

Arguments index <code>number</code> Must be valid. <p>No return value.</p> <p>Example</p> <pre><code>var count = plman.RecyclerCount;
if (count &gt; 0) {
// restore first deleted playlist
plman.RecyclerRestore(0);
}
</code></pre>

Arguments playlistIndexes <code>array</code> <p>Returns a <code>boolean</code> value.</p> <p>Example</p> <pre><code>// This would remove all empty playlists.
var arr = [];
for (var i = 0; i &lt; plman.PlaylistCount; i++) {
if (plman.GetPlaylistItemCount(i) == 0) arr.push(i);
}
if (arr.length) plman.RemovePlaylists(arr);
</code></pre>

Arguments playlistIndex <code>number</code> Must be valid. crop <code>boolean</code> Default <code>false</code>. <p>No return value.</p> <p>Example</p> <pre><code>// Removes selected items from playlist.
plman.RemovePlaylistSelection(plman.ActivePlaylist);

// Removes items that are NOT selected.
plman.RemovePlaylistSelection(plman.ActivePlaylist, true);
</code></pre>

