Arguments text <code>string</code> font_name <code>string</code> font_size <code>number</code> font_weight DWRITE_FONT_WEIGHT Default <code>400</code>. font_style DWRITE_FONT_STYLE Default <code>0</code>. font_stretch DWRITE_FONT_STRETCH Default <code>5</code>. text_alignment DWRITE_TEXT_ALIGNMENT Default <code>0</code>. paragraph_alignment DWRITE_PARAGRAPH_ALIGNMENT Default <code>0</code>. word_wrapping DWRITE_WORD_WRAPPING Default <code>0</code>.  3.0.13, 3.1.11 trimming_granularity DWRITE_TRIMMING_GRANULARITY Default <code>0</code>. <p>Returns an ITextLayout instance.</p> <p>You typically use this when you want to calculate the height of a string that wraps over multiple lines or need scrolling. When passing to IJSGraphics WriteTextLayout, you can supply a vertical offset.</p> <p>Example</p> <pre><code>// ==PREPROCESSOR==
// @name "SimpleScroll"
// @author "marc2003"
// @import "%fb2k_component_path%helpers.txt"
// ==/PREPROCESSOR==

var text = 'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat. Duis aute irure dolor in reprehenderit in voluptate velit esse cillum dolore eu fugiat nulla pariatur. Excepteur sint occaecat cupidatat non proident, sunt in culpa qui officia deserunt mollit anim id est laborum.';
var layout = utils.CreateTextLayout(text, 'Segoe UI', 24);
var offset = 0;
var text_height = 0;

var box = {
x : 50,
y : 50,
w : 0,
h : 0,
}

function on_paint(gr) {
gr.DrawRectangle(box.x, box.y, box.w, box.h, 1, RGB(255, 0, 0));
gr.WriteTextLayout(layout, RGB(0, 0, 0), box.x, box.y, box.w, box.h, offset);
}

function on_mouse_wheel(step) {
if (text_height &lt; box.h) return;
offset += step * 60;
if (offset &gt; 0) offset = 0;
else if (offset &lt; box.h - text_height) offset = box.h - text_height;
window.Repaint();
}

function on_size() {
box.w = window.Width / 2;
box.h = window.Height / 2;
text_height = layout.CalcTextHeight(box.w);
if (text_height &lt; box.h) offset = 0;
else if (offset &lt; box.h - text_height) offset = box.h - text_height;
}
</code></pre>

Arguments str <code>string</code> Must be in full <code>YYYY-MM-DD HH:MM:SS</code> format. <p>The return value is seconds since 00:00:00 Thursday, 1 January 1970 UTC.</p> <p>It is expected date strings are timezone adjusted but timestamps are UTC (not adjusted).</p> <p>Example</p> <pre><code>var last_played_string = "2018-08-30 00:00:00";
